#!/usr/bin/env bash
# Rebuild falcon-mamba-7b.knot and mamba-2.8b.knot with fixed tensor name patterns.
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
DI="$SCRIPT_DIR/distributed-inference"
YAML="$SCRIPT_DIR/cloudbuild-ssm-reencode.yaml"

TMPDIR="$(mktemp -d)"
trap 'rm -rf "$TMPDIR"' EXIT

mkdir -p "$TMPDIR/open-source/gnosis/distributed-inference"

cp "$YAML"                     "$TMPDIR/"
cp "$DI/encode-ssm-models.py"  "$TMPDIR/open-source/gnosis/distributed-inference/"
cp "$DI/encode-knot.py"        "$TMPDIR/open-source/gnosis/distributed-inference/"
cp "$DI/upload-to-r2.py"       "$TMPDIR/open-source/gnosis/distributed-inference/"

echo "[submit] tmpdir contents:"
find "$TMPDIR" -type f | sort

echo "[submit] submitting build (models=falcon-mamba-7b mamba-2.8b)"
gcloud builds submit "$TMPDIR" \
  --config="$TMPDIR/cloudbuild-ssm-reencode.yaml" \
  --project=neutral-418500 \
  --async
